module top_module(
    inv_X ,
    A1,
    A2,
    B1,
    B2
);output inv_X ;
    input  A1;
    input  A2;
    input  B1;
    input  B2;

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    assign inv_X = ((A1 & ~A2) | (B1 & ~B2) | (~A1 & ~A2 & ~B1 & ~B2)) ? 1'b1 : 1'b0;

endmodule
